<template lang="en">
<section>
    <div class="my-popups">
        <loader :is-visible="isLoading" />

        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">

                    <div class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                        <h5 class="modal-title">{{ EditData.length > 0 ?  $t('Update')  :  $t('Manage') }}</h5>
                        <span class="user-guide">
                            <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG"
                                role="button" aria-expanded="false" aria-controls="collapseExample"> <em
                                    class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                            <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                    <div class="con" v-html="getUserGuideTitle()"></div>
                                </div>
                            </div>
                        </span>
                        <button type="button" class="close" @click="Close">
                            <em class="fa fa-times"></em>
                        </button>
                    </div>

                    <div class="modal-body">
                        <dynamic-form lang="en" ref="ClientFlag" :buttons="buttons" :schema="FormSchema" :mandatorytext="$t('MandatoryString')">
                            <template v-slot:tgslot-flagCondition="{data}">
                                <div class="col-lg-12 manage-color">
                                    <div class="row mng-number mb-1 align-items-stretch mx-0 divclone" id="divclone" data-index="0">

                                        <!-- Number Box -->
                                        

                                        <!-- Content -->
                                        <div class="col-lg-11 p-3">
                                            <div class="row">

                                                <!-- WHEN Header -->
                                                <div class="col-lg-12 mb-2">
                                                    <div class="heading-border mb-2">
                                                        <h5 class="h5">
                                                            <span>When</span>
                                                            <small class="float-right">
                                                                <a href="javascript:;" class="delflagcondition" style="display:none;">
                                                                    <i class="fa fa-trash pr-2"></i>Delete
                                                                </a>
                                                            </small>
                                                        </h5>
                                                    </div>
                                                </div>

                                                <!-- Service Name -->
                                                <div class="col-lg-10">
                                                    <label>Service Name:<span class="mandatory">*</span></label>
                                                    <Field name="ServiceName" :rules="{ required: true }" v-slot="{ errors }">
                                                        <div class="form-group">
                                                            <div class="input-group mb-3">
                                                                <select name="ServiceName" class="form-control" :class="{ 'is-invalid': errors[0] }" v-model="ServiceId" @change="handleTemplateChange(data.fieldInfo.value)">
                                                                    <option value="">{{ $t('Select') }}</option>
                                                                    <option v-for="(item) in ServiceList"  :value="item.value">
                                                                        {{ item.name }}
                                                                    </option>
                                                                </select>
                                                                <span v-if="errors[0]" class="invalid-feedback d-block">
                                                                    {{ errors[0] }}
                                                                </span>
                                                            </div>
                                                        </div>
                                                    </Field>
                                                </div>

                                                <!-- Status -->
                                                <div class="col-lg-2">
                                                    <label>Status:<span class="mandatory">*</span></label>
                                                    <Field name="Status" :rules="{ required: true }" v-slot="{ errors }">
                                                        <div class="form-group">
                                                            <div class="input-group mb-3">
                                                                <select name="Status" class="form-control" :class="{ 'is-invalid': errors[0] }" v-model="StatusId" @change="handleTemplateChange(StatusId)">
                                                                    <option v-for="(item, idx) in StatusData" :key="idx" :value="item.STATUS_ID">
                                                                        {{ item.STATUS }}
                                                                    </option>
                                                                </select>
                                                                <span v-if="errors[0]" class="invalid-feedback d-block">
                                                                    {{ errors[0] }}
                                                                </span>
                                                            </div>
                                                        </div>
                                                    </Field>
                                                </div>

                                                <!-- THEN Section -->
                                                <div class="col-lg-12 divthen">
                                                    <div class="row">

                                                        <div class="col-lg-12 mb-2">
                                                            <div class="heading-border mb-2">
                                                                <h5 class="h5"><span>Then</span></h5>
                                                            </div>
                                                        </div>

                                                        <div class="col-lg-12 divthenchange">
                                                            <div class="row divchange" v-for="(item, index) in Mainleveldiv" :key="index">
                                                                <div class="col-lg-1 mt-3 d-flex align-items-center">
                                                                    <h4 class="w-100" >{{index+1}}</h4>
                                                                </div>
                                                                <!-- Change -->
                                                                <div class="col-lg-4">
                                                                    <div class="form-group">
                                                                        <label>Change:<span class="mandatory">*</span></label>

                                                                        <Field :name="'Change_' + index" :rules="{ required: true }" v-slot="{ errors }">
                                                                            <div class="form-group">
                                                                                <div class="input-group mb-3">
                                                                                    <select class="form-control" :class="{ 'is-invalid': errors[0] }" v-model="item.TempId" @change="GetFlagFieldListDropdown(index, item.TempId)">

                                                                                        <option value="">{{ $t('Select') }}</option>
                                                                                        <option v-for="(ch, idx) in ChangeFieldData" :key="idx" :value="ch.TEMPLATE_ID">
                                                                                            {{ ch.DISPLAY_NAME }}
                                                                                        </option>
                                                                                    </select>

                                                                                    <span v-if="errors[0]" class="invalid-feedback d-block">
                                                                                        {{ errors[0] }}
                                                                                    </span>
                                                                                </div>
                                                                            </div>
                                                                        </Field>
                                                                    </div>
                                                                </div>

                                                                <!-- To -->
                                                                <div class="col-lg-4">
                                                                    <div class="form-group">
                                                                        <label>To:<span class="mandatory">*</span></label>

                                                                        <Field :name="'To_' + index" :rules="{ required: true }" v-slot="{ errors }">
                                                                            <div class="form-group">
                                                                                <div class="input-group mb-3">
                                                                                    <select class="form-control" :class="{ 'is-invalid': errors[0] }" v-model="item.ToId" @change="UpdateSelectedToData(item)">

                                                                                        <option value="">{{ $t('Select') }}</option>

                                                                                        <!-- FIX: Use item.ToData -->
                                                                                        <option v-for="(t, idx) in item.ToData" :key="idx" :value="t.VALUE">
                                                                                            {{ t.NAME }}
                                                                                        </option>
                                                                                    </select>
                                                                                    <span v-if="errors[0]" class="invalid-feedback d-block">
                                                                                        {{ errors[0] }}
                                                                                    </span>
                                                                                </div>
                                                                            </div>
                                                                        </Field>
                                                                    </div>
                                                                </div>

                                                                <!-- Buttons -->
                                                                <div class="col-lg-2 mng-btn">
                                                                    <label></label>
                                                                    <div class="input-group">
                                                                        <em class="btn btn-primary mb-2" v-if="index == 0" @click="addRow">
                                                                            <i class="fa fa-plus font-20 mt-1"></i>
                                                                        </em>
                                                                        <em class="btn btn-danger mb-2" v-if="index != 0" @click="deleteRow(index)">
                                                                            <i class="fa fa-trash font-20 mt-1"></i>
                                                                        </em>
                                                                    </div>
                                                                </div>

                                                            </div>

                                                        </div>

                                                    </div>
                                                </div>
                                            </div>
                                        </div>

                                    </div>
                                </div>
                            </template>
                        </dynamic-form>
                    </div>

                </div>
            </div>
        </div>

    </div>
</section>
</template>

<script>

import DataService from '../../services/DataService';
import { locateBillingService} from '../../services/locateBillingService';

export default {
    props: {
        EditData: {
            type: Array,
            required: false,
        },
    },
    data() {
        return {
            isLoading: false,
            ClientNameData: [],
            clientList: [],
            groupedUtilities: [],
            StatusData: [],
            FindalLocationArray: [],
            BillRule: [],
            ServiceList: [],
            ServiceId: '',
            ChangeFieldData: [],
            Mainleveldiv: [{
                TempId: [],
                TEMPLATE_ID: "",
                ToId: [],
                NAME: '',
                VALUE: null,
                ToData: []
            }],
            PageSize: 100,
            PageNumber: 1,
            searchCondition: '',
            GroupNewData: [],
            FormLabel: 'Automate Flag',
            StatusId: 1001,
            setupId: null,
            isShowUnit: true,
            isGroupBy: false,
            isComboChargeScope: false,
            FormSchema: [{
                    layoutType: "double",
                    Data: [

                        {
                            astype: "SearchableSelectField",
                            label: this.$t('SelectClient'),
                            name: "Client",
                            value: "",
                            placeholder: this.$t('SelectClient'),
                            disabled: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                groupFields: ['groupText'],
                                itemFields: ['text'],
                                isMultiple: false,
                                maxRenderItems: 50,
                                lazyLoad: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.GetBillingRuleByClient
                            },
                            validationRules: {
                                required: true
                            },

                        },
                        {
                            astype: "SelectField",
                            label: this.$t('BillingRuleName'),
                            name: "RuleName",
                            value: "",
                            placeholder: this.$t('BillingRuleName'),
                            disabled: false,
                            config: {
                                options: [],
                                onChange: this.GetFlagFrom

                            },
                            validationRules: {
                                required: true
                            },

                        }

                    ]
                },
                {
                    group_name: "Flag Condition",
                    layoutType: "single",
                    Data: [{
                        astype: "SlotField",
                        name: "flagCondition",
                        value: "",
                        visibility: false,
                        config: {
                            options: [],
                            onChange: this.InvoiceComponentFieldsValues,
                        },
                        //validationRules: { "required": true, max: 100 },
                    }, ]
                }

            ],
            buttons: [{
                    type: "button",
                    class: "btn btn-primary",
                    isVisible: false,
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('AddAdditionalFlagCondition'),
                    onClick: this.AddAdditionalFlag
                },
                {
                    type: "submit",
                    class: "btn btn-success",
                    isVisible: true,
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('SaveRule'),
                    onClick: this.SaveData
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    isVisible: true,
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.Close,
                },
            ],
        };
    },

    created: async function () {
    var vm = this;
    vm.GetStatusList();
    await vm.GetDDLCompanyContractClients();

    if (vm.EditData.length > 0 && vm.EditData[0].CLIENT_FLAG_ID > 0) {
        (vm.FormSchema)[0].Data[0].value = vm.EditData[0].CLIENT_ID;
        await vm.GetBillingRuleByClient('client', vm.EditData[0].CLIENT_ID);
        (vm.FormSchema)[0].Data[1].value = vm.EditData[0].CONFIGURATION_ID;
        await vm.GetFlagFrom();
        setTimeout(() => {
            vm.ServiceId = vm.EditData[0].SERVICE_ID;
            vm.StatusId = vm.EditData[0].STATUS_ID;
        }, 300);

        setTimeout(() => {
            debugger;
            vm.Mainleveldiv = vm.EditData.map(item => ({
                TempId: Number(item.template_id),
                TEMPLATE_ID: '',
                ToId: item.FIELD_VALUE,
                NAME: item.FIELD_NAME,
                VALUE: null,
                ToData: []
            }));
            vm.$nextTick(() => {
                let templateNotFound = false; 
                
                vm.Mainleveldiv.forEach((row, index) => {
                    vm.GetFlagFieldListDropdown(index, row.TempId, true);
                    if (!row.TempId && !templateNotFound) {
                        vm.ShowAlert(vm.$t('TemplatenotfoundPleasecontacttheadministrator', [vm.$t('Flag')]), "failure", true, vm.$t("Alert"));
                        templateNotFound = true;
                    }
                });
            });
        }, 400);
    }
},


    methods: {
        getUserGuideTitle() {
            let text = this.$t('USER_GUIDE_CLIENT_FLAG'); ;
            return text
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },
        Close() {
            this.$emit('CloseAddFlag');
        },
        AddAdditionalFlag() {
            var vm = this;
            vm.ShowAlert(vm.$t('Nomoreflagconditionexist', [vm.$t('Flag')]), "warning", true, vm.$t("Alert"));
        },

        addRow() {
            this.Mainleveldiv.push({
                TempId: [],
                TEMPLATE_ID: "",
                ToId: [],
                NAME: "",
                VALUE: null,
                ToData: []
            });
        },

        deleteRow(index) {
            if (this.Mainleveldiv.length > 1) {
                this.Mainleveldiv.splice(index, 1);
            }
        },

        handleTemplateChange() {

        },

        GetBillingRuleByClient: async function (value, x) {
            var vm = this;
            var clientId = '';
            if (value === 'client' && x === '' && arguments.length > 2) {
                // Called from edit mode: GetBillingRuleByClient('client','',clientId)
                clientId = arguments[2];
            } else if (x !== undefined && x !== null && x !== '') {
                clientId = x;
            } else if (value !== undefined && value !== null && value !== '') {
                clientId = Array.isArray(value) ? value[0] : value;
            } else {
                // Try to get from form schema value
                var clientField = (vm.FormSchema)[0].Data[0];
                if (clientField && clientField.value) {
                    clientId = Array.isArray(clientField.value) ? clientField.value[0] : clientField.value;
                }
            }

            if (!clientId || clientId === '') {
                // Clear billing rule options if no client selected
                if (vm.$refs.ClientFlag) {
                    vm.$refs.ClientFlag.updateProperty("RuleName", "config.options", []);
                    vm.$refs.ClientFlag.UpdateKeyValue();
                }
                return;
            }
            var url = `clientId=${clientId}`;
            vm.isLoading = true;
            await DataService.GetBillingRuleByClient(url).then((response) => {
                if (response.data && response.data.result && response.data.result.length > 0) {
                    vm.BillRule =  response.data.result;
                    var billingRuleOptions = [];
                    vm.BillRule.forEach((itm, index) => {
                        billingRuleOptions.push({
                            name: `${itm.BILLING_CONFIG_NAME}`,
                            value: `${itm.CONFIGURATION_ID}`
                        })
                    });
                    // Use updateProperty to update the form field options (same as ChangeClientAndUtility.vue)
                    if (vm.$refs.ClientFlag) {
                        vm.$refs.ClientFlag.updateProperty("RuleName", "config.options", billingRuleOptions);
                        vm.$refs.ClientFlag.UpdateKeyValue();
                    }
                } else {
                    // Clear options if no results
                    if (vm.$refs.ClientFlag) {
                        vm.$refs.ClientFlag.updateProperty("RuleName", "config.options", []);
                        vm.$refs.ClientFlag.UpdateKeyValue();
                    }
                }
                vm.isLoading = false;
            }).catch(error => {
                console.error('Error fetching billing rules:', error);
                // Clear options on error
                if (vm.$refs.ClientFlag) {
                    vm.$refs.ClientFlag.updateProperty("RuleName", "config.options", []);
                    vm.$refs.ClientFlag.UpdateKeyValue();
                }
                vm.isLoading = false;
            });
        },
        GetFlagFrom: async function () {
            var vm = this;
            (vm.FormSchema)[1].Data[0].visibility = true;
            vm.buttons[0].isVisible = true;
            // Get the selected billing rule ID
            var ruleId = vm.FormSchema[0].Data[1].value;
            if (!ruleId || ruleId === '') {
                vm.ShowAlert(vm.$t('PleaseSelectBillingRule'), "warning", true, vm.$t("Alert"));
                return;
            }

            // Load services filtered by rule, status, and fields in parallel
            Promise.all([
                await vm.GetServiceList(ruleId),
                vm.GetStatusList(),
                await vm.GetFieldsListBySetupId()
            ]).catch(error => {
                console.error('Error loading flag form data:', error);
                vm.isLoading = false;
            });
        },
        GetServiceList: function (ruleId) {
            var vm = this;
            vm.isLoading = true;
            // Clear existing options first 
            vm.ServiceList = [];
            if (vm.$refs.ClientFlag) {
                vm.$refs.ClientFlag.updateProperty("ServiceName", "config.options", []);
                vm.$refs.ClientFlag.UpdateKeyValue();
            }

            // Add timeout to prevent hanging
            var timeoutId = setTimeout(function () {
                if (vm.isLoading) {
                    console.warn('GetServiceList is taking too long, cancelling...');
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t('ServiceListLoadTimeout') || 'Service list is taking too long to load. Please try again.', "warning", true, vm.$t("Alert"));
                }
            }, 30000); // 30 second timeout

            // Call LoadFlagList API with ruleId (same as MVC LoadFlagList action)
            var url = `ruleId=${ruleId || 0}`;
            return DataService.LoadFlagList(url).then((response) => {
                clearTimeout(timeoutId);
                vm.isLoading = false;
                // MVC returns array of { Name, Value } objects directly
                if (response && response.data && Array.isArray(response.data) && response.data.length > 0) {
                    vm.ServiceList = response.data;
                    var serviceOptions = [];
                    vm.ServiceList.forEach((itm, index) => {
                        serviceOptions.push({
                            name: itm.Name || itm.name,
                            value: itm.Value || itm.value
                        })
                    });

                    // Use updateProperty for proper reactivity
                    if (vm.$refs.ClientFlag) {
                        vm.$refs.ClientFlag.updateProperty("ServiceName", "config.options", serviceOptions);
                        vm.$refs.ClientFlag.UpdateKeyValue();
                    }
                } else {
                    // No services found for this rule
                    vm.ServiceList = [];
                    if (vm.$refs.ClientFlag) {
                        vm.$refs.ClientFlag.updateProperty("ServiceName", "config.options", []);
                        vm.$refs.ClientFlag.UpdateKeyValue();
                    }
                }
            }).catch(error => {
                clearTimeout(timeoutId);
                console.error('Error fetching service list:', error);
                vm.isLoading = false;
                vm.ServiceList = [];
                if (vm.$refs.ClientFlag) {
                    vm.$refs.ClientFlag.updateProperty("ServiceName", "config.options", []);
                    vm.$refs.ClientFlag.UpdateKeyValue();
                }

                var errorMsg = 'Error loading service list. Please try again.';
                if (error.response && error.response.status === 499) {
                    errorMsg = 'Request timed out. Please try again.';
                } else if (error.response && error.response.data && error.response.data.msg) {
                    errorMsg = error.response.data.msg;
                }
                vm.ShowAlert(errorMsg, "failure", true, vm.$t("Alert"));
            });
        },
        GetStatusList() {
            const vm = this;
            vm.isLoading = true;
            try {
                DataService.GetClientStatusList().then((response) => {
                    const data = JSON.parse(response.data);
                    if (data) {
                        vm.StatusData = data.filter(itm => itm.STATUS_ID === 1001 || itm.STATUS_ID === 1002);
                    }
                    vm.isLoading = false;
                });
            } catch (error) {
                vm.isLoading = false;
            }
        },
        GetDDLCompanyContractClients: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                vm.$refs.ClientFlag.updateProperty("Client", "config.options", vm.clientList);
                vm.$refs.ClientFlag.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = [];
                vm.$refs.ClientFlag.updateProperty("Client", "config.options", vm.clientList);
                vm.$refs.ClientFlag.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },

        GetFieldsListBySetupId: async function () {
            var vm = this;
            vm.isLoading = true;
            var configid = parseFloat(vm.FormSchema[0].Data[1].value);
            var selectedRule = vm.BillRule.find(x => x.CONFIGURATION_ID == configid);
            vm.setupId = selectedRule ? selectedRule.SETUP_ID : null;

            // If no setupId is found — reset and exit
            if (!vm.setupId) {
                vm.ChangeFieldData = [];
                vm.isLoading = false;
                return;
            }

            var url = `setupId=${vm.setupId}&isShowUnit=${vm.isShowUnit}&isGroupBy=${vm.isGroupBy}&isComboChargeScope=${vm.isComboChargeScope}&reqFrom=flag`;

           await DataService.GetFieldsListBySetupId(url).then((response) => {
                if (response.data && response.data.length > 0) {
                    vm.ChangeFieldData = JSON.parse(response.data);

                    // reset Change selections for all rows
                    vm.Mainleveldiv.forEach(i => {
                        i.TempId = "";
                        i.ToData = [];
                        i.ToId = "";
                        i.VALUE = null;
                        i.NAME = '';
                    });

                    vm.$refs.ClientFlag.UpdateKeyValue();
                }

                vm.isLoading = false;
            });
        },

       GetFlagFieldListDropdown(index, item, isEdit = false) {
            const vm = this;
            const rule = vm.ChangeFieldData.find(x => x.TEMPLATE_ID == item);
            const name = rule ? rule.DISPLAY_NAME : null;

            vm.isLoading = true;

            DataService.GetFlagFieldListDropdown(`reqFrom=${name}`).then(res => {
                const data = JSON.parse(res.data);

                vm.Mainleveldiv[index].ToData = data;

                // ❗ Reset only in create mode
                if (!isEdit) {
                    vm.Mainleveldiv[index].ToId = "";
                    vm.Mainleveldiv[index].NAME = "";
                    vm.Mainleveldiv[index].VALUE = "";
                } else {
                    // 🔹 Auto-bind NAME/VALUE in edit
                    const selected = data.find(d => d.VALUE == vm.Mainleveldiv[index].ToId);
                    if (selected) {
                        vm.Mainleveldiv[index].NAME = selected.NAME;
                        vm.Mainleveldiv[index].VALUE = selected.VALUE;
                    }
                }

                vm.isLoading = false;
            });
        },

        UpdateSelectedToData(item) {
            const selected = item.ToData.find(t => t.VALUE == item.ToId);
            if (selected) {
                item.NAME = selected.NAME;
                item.VALUE = selected.VALUE;
            } else {
                item.NAME = "";
                item.VALUE = "";
            }
        },

        async SaveData() {
            var vm = this;
            const result = await vm.$refs.ClientFlag.validateForm.validate();
            if (result) {
                const objData = {
                    ClientFlagId: vm.EditData.length > 0 ? vm.EditData[0].CLIENT_FLAG_ID : 0,
                    ClientId: [{
                        value: Number(vm.FormSchema[0].Data[0].value) || 0
                    }],
                    RoleId: Number(vm.FormSchema[0].Data[1].value) || 0,
                    ServiceId:String(vm.ServiceId) || 0,
                    SetupId: Number(vm.setupId) || 0,
                    Status: vm.StatusId || 1001,
                    Mainleveldiv: vm.Mainleveldiv
                }
                var obj = JSON.stringify(objData);
                var params = `objData=${encodeURIComponent(obj)}`;
                await DataService.SaveUpdateFlagData(obj).then(response => {
                    if (response.data != null) {
                        const Result = JSON.parse(response.data)[0];
                        if (Result.Success == 1) {
                            vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Flag')]), "success", true, vm.$t("Alert"));
                            vm.Close();
                        } else if (Result.Success == 2) {
                            vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Flag')]), "Success", true, vm.$t('Alert'));
                            vm.Close();
                        } else if (Result.Success == 0 && Result.Error == 'EXISTS') {
                            vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Flag')]), "warning", true, vm.$t("Alert"));
                        } else {
                            vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
                        }
                    }
                });

            }
        },

    }
};
</script>
